import{_ as i,c as a,o as s,aj as t}from"./chunks/framework.HLg5PcC2.js";const c=JSON.parse('{"title":"Starting with the Template App","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/template-app.md","filePath":"getting-started/template-app.md"}'),n={name:"getting-started/template-app.md"};function l(o,e,r,p,h,d){return s(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="starting-with-the-template-app" tabindex="-1">Starting with the Template App <a class="header-anchor" href="#starting-with-the-template-app" aria-label="Permalink to “Starting with the Template App”">​</a></h1><p>The fastest way to build an app on Primitive is to start from the official template. This guide walks you through creating a new project and running your first app.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisites”">​</a></h2><ul><li><strong>Node.js</strong> ^20.19.0 or &gt;=22.12.0</li><li><strong>GitHub account</strong> (to create your own repository from the template)</li></ul><h2 id="_1-create-your-repository" tabindex="-1">1. Create Your Repository <a class="header-anchor" href="#_1-create-your-repository" aria-label="Permalink to “1. Create Your Repository”">​</a></h2><ol><li>Go to <a href="https://github.com/Primitive-Labs/primitive-app-template" target="_blank" rel="noreferrer">primitive-app-template</a> on GitHub</li><li>Click the green <strong>&quot;Use this template&quot;</strong> button in the upper right</li><li>Choose a name for your new repository and create it</li></ol><h2 id="_2-install-pnpm" tabindex="-1">2. Install pnpm <a class="header-anchor" href="#_2-install-pnpm" aria-label="Permalink to “2. Install pnpm”">​</a></h2><p>This project uses <a href="https://pnpm.io/" target="_blank" rel="noreferrer">pnpm</a> as its package manager. The easiest way to install pnpm is through Corepack (included with Node.js 16+):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">corepack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">corepack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prepare</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pnpm@latest</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --activate</span></span></code></pre></div><p>Alternatively, see the <a href="https://pnpm.io/installation" target="_blank" rel="noreferrer">pnpm installation guide</a> for other methods.</p><h2 id="_3-install-the-primitive-cli" tabindex="-1">3. Install the Primitive CLI <a class="header-anchor" href="#_3-install-the-primitive-cli" aria-label="Permalink to “3. Install the Primitive CLI”">​</a></h2><p>The <code>primitive-admin</code> CLI tool provides command-line access to the Primitive Admin server for managing your app. Install it globally:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> primitive-admin</span></span></code></pre></div><p>Once installed, authenticate with your Primitive account:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span></code></pre></div><p>This will open a browser window for you to sign in. After signing in, you can verify your authentication:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whoami</span></span></code></pre></div><h2 id="_4-clone-your-repository" tabindex="-1">4. Clone Your Repository <a class="header-anchor" href="#_4-clone-your-repository" aria-label="Permalink to “4. Clone Your Repository”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/your-username/my-app.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span></span></code></pre></div><h2 id="_5-install-dependencies" tabindex="-1">5. Install Dependencies <a class="header-anchor" href="#_5-install-dependencies" aria-label="Permalink to “5. Install Dependencies”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h2 id="_6-create-your-app-on-primitive" tabindex="-1">6. Create Your App on Primitive <a class="header-anchor" href="#_6-create-your-app-on-primitive" aria-label="Permalink to “6. Create Your App on Primitive”">​</a></h2><p>You need to create an app in the Primitive Admin system to get an <strong>App ID</strong> for your project.</p><p><strong>Option A: Using the CLI (Recommended)</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;My New App&quot;</span></span></code></pre></div><p>This will output your new <strong>App ID</strong>. You can also list your apps at any time:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p><strong>Option B: Using the Dashboard</strong></p><p>Go to the <a href="https://admin.primitiveapi.com/login" target="_blank" rel="noreferrer">Primitive Admin Console</a> and create a new app through the web interface. Make note of your <strong>App ID</strong>.</p><h2 id="_7-configure-your-environment" tabindex="-1">7. Configure Your Environment <a class="header-anchor" href="#_7-configure-your-environment" aria-label="Permalink to “7. Configure Your Environment”">​</a></h2><p>Open the <code>.env</code> file in your project and update the App ID:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VITE_APP_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-app-id-here</span></span></code></pre></div><h2 id="_8-run-your-app" tabindex="-1">8. Run Your App <a class="header-anchor" href="#_8-run-your-app" aria-label="Permalink to “8. Run Your App”">​</a></h2><p>Start the development server:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>Open <code>http://localhost:5173</code> in your browser. You should see your app running.</p><p><strong>Congratulations!</strong> You now have a working Primitive app with:</p><ul><li>Real-time data sync</li><li>Local-first data persistence</li><li>A Vue + TypeScript + Tailwind foundation</li><li>Built-in test harness for browser-based testing</li><li>Document debugger for inspecting your data</li></ul><h2 id="setting-up-google-sign-in-optional" tabindex="-1">Setting Up Google Sign In (Optional) <a class="header-anchor" href="#setting-up-google-sign-in-optional" aria-label="Permalink to “Setting Up Google Sign In (Optional)”">​</a></h2><p>Google OAuth is optional. If you want to enable Google as a sign-in option for your app, follow these steps.</p><h3 id="_1-configure-google-oauth-client" tabindex="-1">1. Configure Google OAuth Client <a class="header-anchor" href="#_1-configure-google-oauth-client" aria-label="Permalink to “1. Configure Google OAuth Client”">​</a></h3><p>Go to the <a href="https://console.cloud.google.com/auth/clients" target="_blank" rel="noreferrer">Google Cloud Console OAuth page</a> and create a new OAuth client (Web application type):</p><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Authorized JavaScript origins</td><td><code>http://localhost:5173</code></td></tr><tr><td>Authorized redirect URIs</td><td><code>http://localhost:5173/oauth/callback</code></td></tr></tbody></table><p>Save and note your <strong>Client ID</strong> and <strong>Client Secret</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Production Setup</p><p>When deploying to production, you&#39;ll add your production domain to these settings alongside localhost.</p></div><h3 id="_2-enable-google-oauth-in-primitive-admin" tabindex="-1">2. Enable Google OAuth in Primitive Admin <a class="header-anchor" href="#_2-enable-google-oauth-in-primitive-admin" aria-label="Permalink to “2. Enable Google OAuth in Primitive Admin”">​</a></h3><p>Go to the <a href="https://admin.primitiveapi.com/login" target="_blank" rel="noreferrer">Primitive Admin Console</a> and navigate to your app&#39;s settings:</p><ol><li>Open the <strong>Google OAuth</strong> section</li><li>Enable Google OAuth as a sign-in method</li><li>Add your <strong>Google Client ID</strong> and <strong>Client Secret</strong> from step 1</li><li>Add matching origin/callback URLs to match what you configured with Google</li></ol><h2 id="why-vue" tabindex="-1">Why Vue? <a class="header-anchor" href="#why-vue" aria-label="Permalink to “Why Vue?”">​</a></h2><p>The template uses Vue 3 because it produces cleaner, more maintainable code—especially when working with AI coding assistants. Vue&#39;s straightforward reactivity model avoids the complexity of patterns like React&#39;s <code>useEffect</code> chains.</p><div class="tip custom-block"><p class="custom-block-title">Using Other Frameworks</p><p>The core libraries—<strong>js-bao</strong> and <strong>js-bao-wss-client</strong>—are plain JavaScript and work with any framework. If you prefer React, Svelte, Solid, or vanilla JS, you can use these libraries directly. You&#39;ll just need to handle the framework integration yourself rather than using our Vue-specific <code>primitive-app</code> helpers.</p></div><h2 id="what-s-in-the-template" tabindex="-1">What&#39;s in the Template? <a class="header-anchor" href="#what-s-in-the-template" aria-label="Permalink to “What&#39;s in the Template?”">​</a></h2><p>The template gives you a production-ready starting point:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>my-app/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── assets/         # Static images and assets</span></span>
<span class="line"><span>│   ├── components/     # Vue components (organized by area)</span></span>
<span class="line"><span>│   ├── components/ui/  # shadcn-vue base components</span></span>
<span class="line"><span>│   ├── composables/    # Vue composables</span></span>
<span class="line"><span>│   ├── config/         # Environment configuration</span></span>
<span class="line"><span>│   ├── layouts/        # Page layout components</span></span>
<span class="line"><span>│   ├── lib/            # Business logic (pure TypeScript)</span></span>
<span class="line"><span>│   ├── models/         # js-bao data models</span></span>
<span class="line"><span>│   ├── pages/          # Route components</span></span>
<span class="line"><span>│   ├── router/         # Vue Router setup</span></span>
<span class="line"><span>│   └── tests/          # Test harness test files</span></span>
<span class="line"><span>├── docs/               # Agent guides for AI coding assistants</span></span>
<span class="line"><span>├── .env                # Development environment variables</span></span>
<span class="line"><span>├── .env.production     # Production environment variables</span></span>
<span class="line"><span>└── wrangler.toml       # Cloudflare deployment config</span></span></code></pre></div><p>Key configuration files:</p><ul><li><strong><code>src/config/envConfig.ts</code></strong> — API URLs, App ID, logging, js-bao configuration</li><li><strong><code>src/models/</code></strong> — Your data models (start here!)</li><li><strong><code>docs/</code></strong> — Guides for AI coding assistants working on your project</li></ul><h2 id="development-workflow" tabindex="-1">Development Workflow <a class="header-anchor" href="#development-workflow" aria-label="Permalink to “Development Workflow”">​</a></h2><h3 id="code-generation" tabindex="-1">Code Generation <a class="header-anchor" href="#code-generation" aria-label="Permalink to “Code Generation”">​</a></h3><p>After creating or modifying js-bao models, run the codegen script to generate TypeScript types and field accessors:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codegen</span></span></code></pre></div><p>This is automatically run when you start the dev server (<code>pnpm dev</code>) but should also be run after any model changes.</p><h3 id="type-checking" tabindex="-1">Type Checking <a class="header-anchor" href="#type-checking" aria-label="Permalink to “Type Checking”">​</a></h3><p>Run type checking to catch errors:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> type-check</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><p>Now that your app is running:</p><ol><li><strong><a href="./local-first-model.html">The Local-First Model</a></strong> — Understand how Primitive apps work</li><li><strong><a href="./understanding-documents.html">Understanding Documents</a></strong> — Learn about documents and sharing</li><li><strong><a href="./working-with-data.html">Working with Data</a></strong> — Create your first data models</li><li><strong><a href="./test-harness.html">Test Harness</a></strong> — Write browser-based tests for your app</li><li><strong><a href="./document-debugger.html">Document Debugger</a></strong> — Inspect and debug your data</li><li><strong><a href="./deploying-to-production.html">Deploying to Production</a></strong> — Deploy your app to Cloudflare Workers</li></ol>`,67)])])}const k=i(n,[["render",l]]);export{c as __pageData,k as default};
